# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch. Follow security best practices.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
import random

app = Flask(__name__)
app.config["SQLALCHEMY_DATABASE_URI"] = "sqlite:///password_reset.db"
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(100), unique=True)
    token = db.Column(db.String(100))

@app.route("/password-reset", methods=["POST"])
def password_reset():
    email = request.json.get("email")
    if not email:
        return jsonify({"error": "Email is required"}), 400
    user = User.query.filter_by(email=email).first()
    if not user:
        return jsonify({"error": "User not found"}), 404
    token = random.randint(100000, 999999)
    user.token = token
    db.session.commit()
    reset_link = f"https://example.com/password-reset?token={token}"
    return jsonify({"message": "Reset link sent to your email"}), 201